class Constants
   method Constants();

   /* response states */
   /* 2xx */
   property string SUCCESS readonly; /* 200 */
   property string NO_CONTENT readonly; /* 204 */
   property string NO_DATA readonly; /* 204 */
   /* 4xx */
   property string BAD_REQUEST readonly; /* 400 */
   property string NOT_AUTHORIZED readonly; /*401 */
   property string FORBIDDEN readonly; /* 403 */ /* using 400 due to bug with 8.61 */
   property string NOT_FOUND readonly; /* 404 */
end-class;


method Constants
   /* response states */
   /* 2xx */
   &SUCCESS = "Success";
   &NO_CONTENT = "NoContent";
   &NO_DATA = "NoData";
   /* 4xx */
   &BAD_REQUEST = "BadRequest";
   &NOT_AUTHORIZED = "NotAuthorized";
   &FORBIDDEN = "Forbidden";
   &NOT_FOUND = "NotFound";
end-method;

import BP4D:Constants;
import PTCBAPPLSVCDEFN:ApplicationServiceBase;


class Operators extends PTCBAPPLSVCDEFN:ApplicationServiceBase
   method invokeService();
   method operatorListResponse();
   method operatorResponse();
   method operatorRolesResponse();
   method operatorFilterResponse();

private
   instance BP4D:Constants &constant;

end-class;


method invokeService
   /+ Extends/implements PTCBAPPLSVCDEFN:ApplicationServiceBase.invokeService +/

   &constant = create BP4D:Constants();

   Evaluate %This.ServiceAPI.HttpMethod
   When = %AppService_HTTP_GET

      Evaluate %This.ServiceAPI.URIIndex
      When = 1 /* operator list*/
         %This.operatorListResponse();
         Break;

      When = 2 /* operator details */
         %This.operatorResponse();
         Break;

      When = 3 /* operator roles */
         %This.operatorRolesResponse();
         Break;

      End-Evaluate;
      Break;

   When = %AppService_HTTP_POST
      Evaluate %This.ServiceAPI.URIIndex
      When = 1 /* filter operator list */
         %This.operatorFilterResponse();
         Break;

      End-Evaluate;
      Break;

   End-Evaluate;
end-method;


method operatorListResponse
   Local JsonArray &operatorList;
   Local SQL &operators;
   Local string &operatorId;

   &operatorList = CreateJsonArray();
   &operators = GetSQL(SQL.BP4D_GET_OPRIDS);

   While &operators.Fetch(&operatorId)
      &operatorList.AddElement(&operatorId);
   End-While;

   If (All(&operatorList.Size)) Then
      %This.ServiceAPI.setOutputParameter("operators", &operatorList);
      %This.ServiceAPI.ResultState = &constant.SUCCESS;
   Else
      %This.ServiceAPI.ResultState = &constant.NO_CONTENT;
   End-If;
end-method;


method operatorResponse
   Local JsonObject &operator;
   Local Record &operatorRec;
   Local string &operatorId;

   &operatorId = %This.ServiceAPI.getTemplateParameter("operatorId");

   If (All(&operatorId)) Then
      &operator = CreateJsonObject();
      &operatorRec = CreateRecord(Record.PSOPRDEFN);
      SQLExec("%SelectAll(:1) where oprid = :2", &operatorRec, &operatorId, &operatorRec);

      If (All(&operatorRec.OPRID.Value)) Then
         &operator.AddProperty("operatorId", &operatorRec.OPRID.Value);
         &operator.AddProperty("employeeId", &operatorRec.EMPLID.Value);
         &operator.AddProperty("operatorDescription", &operatorRec.OPRDEFNDESC.Value);
         &operator.AddProperty("operatorClass", &operatorRec.OPRCLASS.Value);
         &operator.AddProperty("rowSecurityClass", &operatorRec.ROWSECCLASS.Value);
         &operator.AddProperty("processProfileClass", &operatorRec.PRCSPRFLCLS.Value);
         &operator.AddProperty("failedLogins", &operatorRec.FAILEDLOGINS.Value);
         &operator.AddProperty("isLocked", (&operatorRec.ACCTLOCK.Value = 1));
         &operator.AddProperty("lastSignonDatetime", &operatorRec.LASTSIGNONDTTM.Value);

         %This.ServiceAPI.setOutputParameter("operatorDetails", &operator);
         %This.ServiceAPI.ResultState = &constant.SUCCESS;
      Else
         %This.ServiceAPI.ResultState = &constant.NOT_FOUND;
      End-If;
   Else
      %This.ServiceAPI.ResultState = &constant.BAD_REQUEST;
   End-If;
end-method;


method operatorRolesResponse
   Local JsonObject &operator;
   Local JsonArray &roleList;
   Local Record &operatorRec;
   Local SQL &operatorRoles;
   Local string &operatorId, &roleName;

   &operatorId = %This.ServiceAPI.getTemplateParameter("operatorId");

   If (All(&operatorId)) Then
      &operator = CreateJsonObject();
      &roleList = CreateJsonArray();

      &operatorRoles = GetSQL(SQL.BP4D_GET_OPR_ROLES, &operatorId);

      While &operatorRoles.Fetch(&roleName)
         &roleList.AddElement(&roleName);
      End-While;

      &operatorRec = CreateRecord(Record.PSOPRDEFN);
      SQLExec("%SelectAll(:1) where oprid = :2", &operatorRec, &operatorId, &operatorRec);

      If (All(&operatorRec.OPRID.Value)) Then
         &operator.AddProperty("operatorId", &operatorRec.OPRID.Value);
         If (All(&roleList.Size)) Then
            &operator.AddJsonArray("roles", &roleList);

            %This.ServiceAPI.setOutputParameter("operatorRoles", &operator);
            %This.ServiceAPI.ResultState = &constant.SUCCESS;
         Else
            %This.ServiceAPI.ResultState = &constant.NO_CONTENT;
         End-If;
      Else
         %This.ServiceAPI.ResultState = &constant.NOT_FOUND;
      End-If;
   Else
      %This.ServiceAPI.ResultState = &constant.BAD_REQUEST;
   End-If;
end-method;


method operatorFilterResponse

   Local JsonArray &filters;
   Local JsonObject &filter;
   Local integer &i, &index;
   Local array of array of string &fieldValues;
   Local array of string &fieldNames;
   Local string &fieldName;

   &fieldNames = CreateArray("startsWith");
   &fieldValues = CreateArrayRept(CreateArrayRept("", 0), 0);
   &filters = %This.ServiceAPI.getInputParameter("filters");

   For &i = 1 To &filters.Size
      &filter = &filters.GetJsonObject(&i);
      &fieldName = &filter.GetString("fieldname");

      /* supported fieldname? */
      &index = &fieldNames.Find(&fieldName);
      If (None(&index)) Then
         throw CreateException(0, 0, "unsupported fieldname");
      End-If;

      /* only one instance */
      &index = &fieldValues.Find(&fieldName);
      If (None(&index)) Then
         &fieldValues.Push(CreateArray(&fieldName, &filter.GetString("fieldvalue")));
      Else
         throw CreateException(0, 0, "multiple instances of fieldname");
      End-If;
   End-For;

   Local JsonArray &operatorList;
   Local SQL &operators;
   Local string &operatorId, &likeCriterion;

   &operatorList = CreateJsonArray();

   &likeCriterion = RTrim(&fieldValues [1][2]);
   If (None(&likeCriterion)) Then
      &likeCriterion = "%";
   End-If;
   &operators = GetSQL(SQL.BP4D_GET_OPRIDS_FILTERED, &likeCriterion);

   While &operators.Fetch(&operatorId)
      &operatorList.AddElement(&operatorId);
   End-While;

   If (All(&operatorList.Size)) Then
      %This.ServiceAPI.setOutputParameter("operators", &operatorList);
      %This.ServiceAPI.ResultState = &constant.SUCCESS;
   Else
      %This.ServiceAPI.ResultState = &constant.NO_CONTENT;
   End-If;


end-method;

import BP4D:Constants;
import PTCBAPPLSVCDEFN:ApplicationServiceBase;


class OperatorsDocument extends PTCBAPPLSVCDEFN:ApplicationServiceBase
   method invokeService();
   method operatorListResponse();
   method operatorResponse();
   method operatorRolesResponse();
   method operatorFilterResponse();

private
   instance BP4D:Constants &constant;

end-class;


method invokeService
   /+ Extends/implements PTCBAPPLSVCDEFN:ApplicationServiceBase.invokeService +/

   &constant = create BP4D:Constants();

   Evaluate %This.ServiceAPI.HttpMethod
   When = %AppService_HTTP_GET

      Evaluate %This.ServiceAPI.URIIndex
      When = 1 /* operator list*/
         %This.operatorListResponse();
         Break;

      When = 2 /* operator details */
         %This.operatorResponse();
         Break;

      When = 3 /* operator roles */
         %This.operatorRolesResponse();
         Break;

      End-Evaluate;

      Break;

   When = %AppService_HTTP_POST
      Evaluate %This.ServiceAPI.URIIndex
      When = 1 /* filter operator list */
         %This.operatorFilterResponse();
         Break;
      End-Evaluate;

      Break;

   End-Evaluate;
end-method;


method operatorListResponse
   Local Document &operatorList;
   Local Compound &operatorCompound;
   Local Collection &operatorCollection;
   Local Primitive &operator;
   Local boolean &succes;
   Local SQL &operators;
   Local string &operatorId;


   &operatorList = CreateDocument("BP4D", "OperatorList", "v1");
   &operatorCompound = &operatorList.DocumentElement;
   &operatorCollection = &operatorCompound.GetPropertyByName("operatorCollection");

   &operators = GetSQL(SQL.BP4D_GET_OPRIDS);

   While &operators.Fetch(&operatorId)
      &operator = &operatorCollection.CreateItem();
      &operator.Value = &operatorId;
      &succes = &operatorCollection.AppendItem(&operator);
   End-While;

   If (All(&operatorCollection.Count)) Then
      %This.ServiceAPI.setOutputParameter("operatorsDoc", &operatorList);
      %This.ServiceAPI.ResultState = &constant.SUCCESS;
   Else
      %This.ServiceAPI.ResultState = &constant.NO_CONTENT;
   End-If;
end-method;

method operatorResponse
end-method;

method operatorRolesResponse
end-method;

method operatorFilterResponse
end-method;

import BP4D:Constants;
import PTCBAPPLSVCDEFN:ApplicationServiceBase;


class Roles extends PTCBAPPLSVCDEFN:ApplicationServiceBase
   method invokeService();
   method roleListResponse();
   method roleResponse();
   method rolePermissionsResponse();

private
   instance BP4D:Constants &constant;

end-class;


method invokeService
   /+ Extends/implements PTCBAPPLSVCDEFN:ApplicationServiceBase.invokeService +/

   &constant = create BP4D:Constants();

   Evaluate %This.ServiceAPI.HttpMethod
   When = %AppService_HTTP_GET

      Evaluate %This.ServiceAPI.URIIndex
      When = 1 /* role list*/
         %This.roleListResponse();
         Break;

      When = 2 /* role details */
         %This.roleResponse();
         Break;

      When = 3 /* role permissions */
         %This.rolePermissionsResponse();
         Break;

      End-Evaluate;
      Break;

   End-Evaluate;
end-method;


method roleListResponse
   Local JsonArray &roleList;
   Local SQL &roles;
   Local string &roleName;

   &roleList = CreateJsonArray();
   &roles = GetSQL(SQL.BP4D_GET_ROLES);

   While &roles.Fetch(&roleName)
      &roleList.AddElement(&roleName);
   End-While;

   If (All(&roleList.Size)) Then
      %This.ServiceAPI.setOutputParameter("roles", &roleList);
      %This.ServiceAPI.ResultState = &constant.SUCCESS;
   Else
      %This.ServiceAPI.ResultState = &constant.NO_CONTENT;
   End-If;
end-method;


method roleResponse
   Local JsonObject &role;
   Local Record &roleRec;
   Local string &roleName;

   &roleName = %This.ServiceAPI.getTemplateParameter("roleName");

   If (All(&roleName)) Then
      &role = CreateJsonObject();
      &roleRec = CreateRecord(Record.PSROLEDEFN);
      SQLExec("%SelectAll(:1) where rolename = :2", &roleRec, &roleName, &roleRec);

      If (All(&roleRec.ROLENAME.Value)) Then
         &role.AddProperty("rolename", &roleRec.ROLENAME.Value);
         &role.AddProperty("version", &roleRec.VERSION.Value);
         &role.AddProperty("roleType", &roleRec.ROLETYPE.Value);
         &role.AddProperty("roleDescription", &roleRec.DESCR.Value);
         &role.AddProperty("roleStatus", &roleRec.ROLESTATUS.Value);
         &role.AddProperty("isRoleQueryEnabled", (&roleRec.ROLE_QUERY_RULE_ON.Value = "Y"));
         &role.AddProperty("roleQueryName ", &roleRec.QRYNAME_SEC.Value);
         &role.AddProperty("lastUpdatedDatetime", &roleRec.LASTUPDDTTM.Value);

         %This.ServiceAPI.setOutputParameter("roleDetails", &role);
         %This.ServiceAPI.ResultState = &constant.SUCCESS;
      Else
         %This.ServiceAPI.ResultState = &constant.NOT_FOUND;
      End-If;
   Else
      %This.ServiceAPI.ResultState = &constant.BAD_REQUEST;
   End-If;
end-method;


method rolePermissionsResponse
   Local JsonObject &rolePermissions;
   Local JsonArray &permissionList;
   Local Record &roleRec;
   Local SQL &permissions;
   Local string &roleName, &permissionName;


   &roleName = %This.ServiceAPI.getTemplateParameter("roleName");

   If (All(&roleName)) Then
      &rolePermissions = CreateJsonObject();
      &permissionList = CreateJsonArray();

      &permissions = GetSQL(SQL.BP4D_GET_ROLE_PERMISSIONS, &roleName);

      While &permissions.Fetch(&permissionName)
         &permissionList.AddElement(&permissionName);
      End-While;

      &roleRec = CreateRecord(Record.PSROLEDEFN);
      SQLExec("%SelectAll(:1) where rolename = :2", &roleRec, &roleName, &roleRec);

      If (All(&roleRec.ROLENAME.Value)) Then
         &rolePermissions.AddProperty("roleName", &roleRec.ROLENAME.Value);
         If (All(&permissionList.Size)) Then
            &rolePermissions.AddJsonArray("permissions", &permissionList);

            %This.ServiceAPI.setOutputParameter("rolePermissions", &rolePermissions);
            %This.ServiceAPI.ResultState = &constant.SUCCESS;
         Else
            %This.ServiceAPI.ResultState = &constant.NO_CONTENT;
         End-If;
      Else
         %This.ServiceAPI.ResultState = &constant.NOT_FOUND;
      End-If;
   Else
      %This.ServiceAPI.ResultState = &constant.BAD_REQUEST;
   End-If;
end-method;

